import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

# Build lookup: {(project_basename, framework, package_id): resolved_version}
def build_lookup(data):
    lookup = {}
    for proj in data['projects']:
        pname = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            for pkg in fw['topLevelPackages']:
                lookup[(pname, fw['framework'], pkg['id'])] = pkg['resolvedVersion']
    return lookup

b = build_lookup(baseline)
a = build_lookup(after)

all_keys = sorted(set(b.keys()) | set(a.keys()))
changes = []
unchanged = []
for k in all_keys:
    bv = b.get(k, 'N/A')
    av = a.get(k, 'N/A')
    if bv != av:
        changes.append((k[0], k[1], k[2], bv, av))
    else:
        unchanged.append((k[0], k[1], k[2], bv))

print('=== CHANGES ===')
if changes:
    for c in changes:
        print(f'  {c[0]:15s} {c[1]:8s} {c[2]:50s} {c[3]:10s} -> {c[4]:10s}')
else:
    print('  None')

print(f'\n=== UNCHANGED ({len(unchanged)} entries) ===')
for u in unchanged:
    print(f'  {u[0]:15s} {u[1]:8s} {u[2]:50s} {u[3]}')
"

